\begin{theorem}
Assuming that \( f \) satisfies a Lipschitz condition, with constant \( L \), the global error satisfies the bound
\[
\| y(x) - \widehat{y}(x) \| \leq 
\begin{cases}
\| y(x_0) - \widehat{y}(x_0) \| + Hm(x - x_0), & L = 0, \\[6pt]
\exp((x - x_0)L) \| y(x_0) - \widehat{y}(x_0) \| + \dfrac{\exp((x - x_0)L) - 1}{L} Hm, & L > 0.
\end{cases}
\]
\end{theorem}
